#!/usr/bin/env python3\n\"\"\"Test enhanced audit logging and permission system.\"\"\"\n\nimport sys\nimport os\nimport asyncio\nimport json\nimport time\nfrom pathlib import Path\n\n# Add the src directory to the path\nsys.path.insert(0, str(Path(__file__).parent / \"src\"))\n\n# Test imports\nfrom ast_grep_mcp.security import (\n    EnhancedAuditLogger, PermissionManager, UserContext, UserRole,\n    SecurityLevel, create_user_context, get_audit_logger, get_permission_manager\n)\n\nasync def test_enhanced_audit_logger():\n    \"\"\"Test enhanced audit logger functionality.\"\"\"\n    print(\"🔍 Testing Enhanced Audit Logger...\")\n    \n    audit_logger = EnhancedAuditLogger()\n    \n    # Create test user contexts\n    user_context = create_user_context(\n        user_id=\"test_user\",\n        role=UserRole.DEVELOPER,\n        session_id=\"session_123\",\n        ip_address=\"192.168.1.100\"\n    )\n    \n    admin_context = create_user_context(\n        user_id=\"admin_user\",\n        role=UserRole.ADMIN,\n        session_id=\"admin_session_456\",\n        ip_address=\"10.0.0.5\"\n    )\n    \n    # Test operation logging\n    event_id = audit_logger.log_operation_start(\n        operation=\"ast_grep_search\",\n        resource=\"/tmp/test_file.js\",\n        user_context=user_context,\n        details={\"pattern\": \"console.log($VAR)\", \"language\": \"javascript\"}\n    )\n    print(f\"✅ Logged operation start: {event_id}\")\n    \n    # Simulate some processing time\n    await asyncio.sleep(0.1)\n    \n    # Test operation completion\n    end_event_id = audit_logger.log_operation_end(\n        operation=\"ast_grep_search\",\n        resource=\"/tmp/test_file.js\",\n        success=True,\n        user_context=user_context,\n        duration_ms=100,\n        resource_usage={\"matches_found\": 5, \"files_scanned\": 10}\n    )\n    print(f\"✅ Logged operation end: {end_event_id}\")\n    \n    # Test permission check logging\n    perm_event_id = audit_logger.log_permission_check(\n        operation=\"ast_grep_run\",\n        resource=\"/etc/sensitive_file\",\n        user_context=user_context,\n        granted=False,\n        reason=\"Insufficient privileges for sensitive path\"\n    )\n    print(f\"✅ Logged permission check: {perm_event_id}\")\n    \n    # Test security violation logging\n    violation_event_id = audit_logger.log_security_violation(\n        violation_type=\"path_traversal_attempt\",\n        operation=\"ast_grep_search\",\n        resource=\"../../../etc/passwd\",\n        user_context=user_context,\n        details={\"attempted_path\": \"../../../etc/passwd\", \"blocked\": True}\n    )\n    print(f\"✅ Logged security violation: {violation_event_id}\")\n    \n    # Test command execution logging\n    cmd_event_id = audit_logger.log_command_execution(\n        command=\"ast-grep\",\n        args=[\"--json\", \"console.log($VAR)\", \"/tmp/test.js\"],\n        working_dir=\"/tmp\",\n        user_context=user_context,\n        success=True,\n        duration_ms=50,\n        return_code=0,\n        resource_usage={\"cpu_time_ms\": 45, \"memory_mb\": 10}\n    )\n    print(f\"✅ Logged command execution: {cmd_event_id}\")\n    \n    # Test event retrieval\n    events = audit_logger.get_events(limit=10)\n    print(f\"✅ Retrieved {len(events)} recent events\")\n    \n    # Test filtered event retrieval\n    security_events = audit_logger.get_events(\n        event_type=\"security_violation\",\n        limit=5\n    )\n    print(f\"✅ Retrieved {len(security_events)} security violation events\")\n    \n    # Test security summary\n    summary = audit_logger.get_security_summary(hours=1)\n    print(f\"✅ Security summary: {summary['total_events']} events, \"\n          f\"{summary['security_violations']} violations, \"\n          f\"{summary['high_risk_events']} high-risk\")\n    \n    # Test high-risk event detection\n    high_risk_event = audit_logger.log_event(\n        event_type=\"security_violation\",\n        operation=\"system_command\",\n        resource=\"/etc/passwd\",\n        success=False,\n        user_context=user_context,\n        security_level=SecurityLevel.CRITICAL,\n        details={\"elevated_privileges\": True, \"system_path_access\": True},\n        error=\"Access denied\",\n        tags={\"critical\", \"potential_breach\"}\n    )\n    print(f\"✅ Logged high-risk event: {high_risk_event}\")\n    \n    return True\n\n\nasync def test_permission_manager():\n    \"\"\"Test permission manager functionality.\"\"\"\n    print(\"\\n🔒 Testing Permission Manager...\")\n    \n    perm_manager = PermissionManager()\n    \n    # Create test user contexts with different roles\n    guest_user = create_user_context(\"guest_user\", UserRole.GUEST)\n    regular_user = create_user_context(\"regular_user\", UserRole.USER)\n    developer_user = create_user_context(\"developer_user\", UserRole.DEVELOPER)\n    admin_user = create_user_context(\"admin_user\", UserRole.ADMIN)\n    \n    test_cases = [\n        # (user_context, operation, resource, expected_result)\n        (guest_user, \"ast_grep_search\", \"/tmp/test.js\", False),  # Guest can't search\n        (regular_user, \"ast_grep_search\", \"/tmp/test.js\", True),   # User can search\n        (regular_user, \"ast_grep_run\", \"/tmp/test.js\", False),     # User can't run\n        (developer_user, \"ast_grep_run\", \"/tmp/test.js\", True),    # Dev can run\n        (developer_user, \"ast_grep_run\", \"/etc/passwd\", False),    # Dev can't access sensitive\n        (admin_user, \"ast_grep_run\", \"/etc/passwd\", True),         # Admin can access anything\n        (regular_user, \"config_modify\", \"config.yml\", False),      # User can't modify config\n        (admin_user, \"config_modify\", \"config.yml\", True),         # Admin can modify config\n    ]\n    \n    for user_context, operation, resource, expected in test_cases:\n        has_permission, reason = perm_manager.check_permission(\n            user_context, operation, resource\n        )\n        \n        status = \"✅\" if has_permission == expected else \"❌\"\n        print(f\"{status} {user_context.role.value} + {operation} + {resource[:20]}... = {has_permission}\")\n        \n        if has_permission != expected:\n            print(f\"   Expected: {expected}, Got: {has_permission}, Reason: {reason}\")\n    \n    return True\n\n\nasync def test_user_context_creation():\n    \"\"\"Test user context creation and permission assignment.\"\"\"\n    print(\"\\n👤 Testing User Context Creation...\")\n    \n    # Test default user creation\n    user = create_user_context(\"test_user\")\n    print(f\"✅ Created default user: {user.user_id}, role: {user.role.value}\")\n    print(f\"   Permissions: {sorted(list(user.permissions))}\")\n    \n    # Test developer user\n    dev_user = create_user_context(\"dev_user\", UserRole.DEVELOPER)\n    print(f\"✅ Created developer: {dev_user.user_id}, role: {dev_user.role.value}\")\n    print(f\"   Permissions: {sorted(list(dev_user.permissions))}\")\n    \n    # Test admin user\n    admin_user = create_user_context(\"admin_user\", UserRole.ADMIN)\n    print(f\"✅ Created admin: {admin_user.user_id}, role: {admin_user.role.value}\")\n    print(f\"   Has wildcard permissions: {'*' in admin_user.permissions}\")\n    \n    # Test permission checking\n    print(f\"\\n🔍 Permission Tests:\")\n    print(f\"   User can read files: {user.has_permission('file.read')}\")\n    print(f\"   User can write files: {user.has_permission('file.write')}\")\n    print(f\"   Dev can write files: {dev_user.has_permission('file.write')}\")\n    print(f\"   Admin can do anything: {admin_user.has_permission('anything')}\")\n    \n    # Test security level access\n    print(f\"\\n🛡️ Security Level Access Tests:\")\n    levels = [SecurityLevel.PUBLIC, SecurityLevel.RESTRICTED, SecurityLevel.SENSITIVE, SecurityLevel.CRITICAL]\n    \n    for level in levels:\n        user_access = user.can_access_security_level(level)\n        dev_access = dev_user.can_access_security_level(level)\n        admin_access = admin_user.can_access_security_level(level)\n        \n        print(f\"   {level.value}: User={user_access}, Dev={dev_access}, Admin={admin_access}\")\n    \n    return True\n\n\nasync def test_global_instances():\n    \"\"\"Test global audit logger and permission manager instances.\"\"\"\n    print(\"\\n🌐 Testing Global Instances...\")\n    \n    # Test global audit logger\n    audit_logger1 = get_audit_logger()\n    audit_logger2 = get_audit_logger()\n    \n    print(f\"✅ Global audit logger singleton: {audit_logger1 is audit_logger2}\")\n    \n    # Test global permission manager\n    perm_manager1 = get_permission_manager()\n    perm_manager2 = get_permission_manager()\n    \n    print(f\"✅ Global permission manager singleton: {perm_manager1 is perm_manager2}\")\n    \n    # Test logging with global instance\n    event_id = audit_logger1.log_event(\n        event_type=\"test_event\",\n        operation=\"global_test\",\n        resource=\"test_resource\",\n        success=True,\n        details={\"test\": \"global instance logging\"}\n    )\n    print(f\"✅ Logged event with global instance: {event_id}\")\n    \n    return True\n\n\nasync def main():\n    \"\"\"Run all audit logging tests.\"\"\"\n    print(\"🧪 Starting Enhanced Audit Logging Tests\\n\")\n    \n    try:\n        await test_enhanced_audit_logger()\n        await test_permission_manager()\n        await test_user_context_creation()\n        await test_global_instances()\n        \n        print(\"\\n🎉 All audit logging tests passed!\")\n        return True\n        \n    except Exception as e:\n        print(f\"\\n❌ Test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\n\nif __name__ == \"__main__\":\n    result = asyncio.run(main())\n    sys.exit(0 if result else 1) 